{
  "data": [{
    "type": "osm",
    "queryArea": { "geocodeArea": "Chicago", "areas": ["Loop"] },
    "outputTableName": "table_osm",
    "autoLoadLayers": { "layers": ["surface", "parks", "water", "roads", "buildings"], "dropOsmTable": true }
  }],
  "compute": [{
    "dataRef": "table_osm_roads",
    "attributes": { "x": "lanes" },
    "outputColumnName": "result",
    "wglsFunction": "if (x <= 0.0) { return 1.0; } if (x > 6.0) { return 6.0; } return x;"
  }],
  "map": {
    "layerRefs": [
      { "dataRef": "table_osm_surface" },
      { "dataRef": "table_osm_parks" },
      { "dataRef": "table_osm_water" },
      { "dataRef": "table_osm_buildings" },
      {
        "dataRef": "table_osm_roads",
        "isPick": true,
        "getFnv": "compute.result",
        "getFnvType": "quantitative",
        "defaultFnv": 1
      }
    ]
  },
  "plot": {
    "dataRef": "table_osm_roads",
    "mark": "bar",
    "axis": ["compute.result", "@transform"],
    "title": "Chicago Loop road capacity (lanes)",
    "transform": { "preset": "binning-1d", "options": { "bins": 6 } },
    "events": ["brushX"],
    "mapRef": "table_osm_roads"
  }
}
